6	
7	package execution
8	
9	import (
10		"fmt"
11		"path/filepath"
12		"strconv"
13		"strings"
14	
15		"github.com/getgauge/gauge-proto/go/gauge_messages"
16		"github.com/getgauge/gauge/config"
17		"github.com/getgauge/gauge/execution/event"
18		"github.com/getgauge/gauge/execution/result"
19		"github.com/getgauge/gauge/filter"
20		"github.com/getgauge/gauge/gauge"
21		"github.com/getgauge/gauge/logger"
22		"github.com/getgauge/gauge/parser"
23		"github.com/getgauge/gauge/plugin"
24		"github.com/getgauge/gauge/runner"
25		"github.com/getgauge/gauge/validation"
26	)
27	
28	type specExecutor struct {
29		specification        *gauge.Specification
30		runner               runner.Runner
31		pluginHandler        plugin.Handler
32		currentExecutionInfo *gauge_messages.ExecutionInfo
33		specResult           *result.SpecResult
34		errMap               *gauge.BuildErrors
35		stream               int
36		scenarioExecutor     executor
37	}
38	
39	func newSpecExecutor(s *gauge.Specification, r runner.Runner, ph plugin.Handler, e *gauge.BuildErrors, stream int) *specExecutor {
40		ei := &gauge_messages.ExecutionInfo{
41			CurrentSpec: &gauge_messages.SpecInfo{
42				Name:     s.Heading.Value,
43				FileName: s.FileName,
44				IsFailed: false,
45				Tags:     getTagValue(s.Tags)},
46			ProjectName:              filepath.Base(config.ProjectRoot),
47			NumberOfExecutionStreams: int32(NumberOfExecutionStreams),
48			RunnerId:                 int32(stream),
49			ExecutionArgs:            gauge.ConvertToProtoExecutionArg(ExecutionArgs),
50		}
51	
52		return &specExecutor{
53			specification:        s,
54			runner:               r,
55			pluginHandler:        ph,
56			errMap:               e,
57			stream:               stream,
58			currentExecutionInfo: ei,
59			scenarioExecutor:     newScenarioExecutor(r, ph, ei, e, s.Contexts, s.TearDownSteps, stream),
60		}
61	}
62	
63	func (e *specExecutor) execute(executeBefore, execute, executeAfter bool) *result.SpecResult {
64		e.specResult = gauge.NewSpecResult(e.specification)
65		if e.runner.Info().Killed {
66			e.specResult.SetSkipped(true)
67			return e.specResult
68		}
69		if errs, ok := e.errMap.SpecErrs[e.specification]; ok {
70			if hasParseError(errs) {
71				e.failSpec()
72				return e.specResult
73			}
74		}
75		lookup, err := e.dataTableLookup()
76		if err != nil {
77			logger.Fatalf(true, "Failed to resolve Specifications : %s", err.Error())
78		}
79		resolvedSpecItems, err := resolveItems(e.specification.GetSpecItems(), lookup, e.setSkipInfo)
80		if err != nil {
81			logger.Fatalf(true, "Failed to resolve Specifications : %s", err.Error())
82		}
83		e.specResult.AddSpecItems(resolvedSpecItems)
84		if executeBefore {
85			event.Notify(event.NewExecutionEvent(event.SpecStart, e.specification, e.specResult, e.stream, e.currentExecutionInfo))
86			if _, ok := e.errMap.SpecErrs[e.specification]; !ok {
87				if res := e.initSpecDataStore(); res.GetFailed() {
88					e.skipSpecForError(fmt.Errorf("Failed to initialize spec datastore. Error: %s", res.GetErrorMessage()))
89				} else {
90					e.notifyBeforeSpecHook()
91				}
92			} else {
93				e.specResult.SetSkipped(true)
94				e.specResult.Errors = e.convertErrors(e.errMap.SpecErrs[e.specification])
95			}
96		}
97		if execute && !e.specResult.GetFailed() {
98			if e.specification.DataTable.Table.GetRowCount() == 0 {
99				others, tableDriven := parser.FilterTableRelatedScenarios(e.specification.Scenarios, func(s *gauge.Scenario) bool {
100					return s.ScenarioDataTableRow.IsInitialized()
101				})
102				results, err := e.executeScenarios(others)
103				if err != nil {
104					logger.Fatalf(true, "Failed to resolve Specifications : %s", err.Error())
105				}
106				e.specResult.AddScenarioResults(results)
107				e.executeScenarioTableDrivenScenarios(tableDriven)
108			} else {
109				err := e.executeSpec()
110				if err != nil {
111					logger.Fatalf(true, "Failed to execute Specification %s : %s", e.specification.Heading.Value, err.Error())
112				}
113			}
114		}
115		e.specResult.SetSkipped(e.specResult.Skipped || e.specResult.ScenarioSkippedCount == len(e.specification.Scenarios))
116		if executeAfter {
117			if _, ok := e.errMap.SpecErrs[e.specification]; !ok {
118				e.notifyAfterSpecHook()
119			}
120			event.Notify(event.NewExecutionEvent(event.SpecEnd, e.specification, e.specResult, e.stream, e.currentExecutionInfo))
121		}
122		return e.specResult
123	}
124	
125	func (e *specExecutor) executeTableRelatedScenarios(scenarios []*gauge.Scenario) error {
126		if len(scenarios) > 0 {
127			index := e.specification.Scenarios[0].SpecDataTableRowIndex
128			sceRes, err := e.executeScenarios(scenarios)
129			if err != nil {
130				return err
131			}
132			specResult := [][]result.Result{sceRes}
133			e.specResult.AddTableRelatedScenarioResult(specResult, index)
134		}
135		return nil
136	}
137	
138	func (e *specExecutor) executeSpec() error {
139		parser.GetResolvedDataTablerows(e.specification.DataTable.Table)
140		nonTableRelatedScenarios, tableRelatedScenarios := parser.FilterTableRelatedScenarios(e.specification.Scenarios, func(s *gauge.Scenario) bool {
141			return s.SpecDataTableRow.IsInitialized()
142		})
143	
144		others, scenarioTableDriven := parser.FilterTableRelatedScenarios(nonTableRelatedScenarios, func(s *gauge.Scenario) bool {
145			return s.ScenarioDataTableRow.IsInitialized()
146		})
147	
148		res, err := e.executeScenarios(others)
149		if err != nil {
150			return err
151		}
152		e.specResult.AddScenarioResults(res)
153		e.executeScenarioTableDrivenScenarios(scenarioTableDriven)
154		err = e.executeTableRelatedScenarios(tableRelatedScenarios)
155		if err != nil {
156			return err
157		}
158		return nil
159	}
160	
161	func (e *specExecutor) executeScenarioTableDrivenScenarios(scenarios []*gauge.Scenario) {
162		scnMap := make(map[int]bool)
163		for _, s := range scenarios {
164			if _, ok := scnMap[s.Span.Start]; !ok {
165				scnMap[s.Span.Start] = true
166			}
167			r, err := e.executeScenario(s)
168			if err != nil {
169				logger.Fatalf(true, "Failed to resolve Specifications : %s", err.Error())
170			}
171			e.specResult.AddTableDrivenScenarioResult(r, gauge.ConvertToProtoTable(s.DataTable.Table),
172				s.ScenarioDataTableRowIndex, s.SpecDataTableRowIndex, s.SpecDataTableRow.IsInitialized())
173		}
174		e.specResult.ScenarioCount += len(scnMap)
175	}
176	
177	func (e *specExecutor) initSpecDataStore() *gauge_messages.ProtoExecutionResult {
178		initSpecDataStoreMessage := &gauge_messages.Message{MessageType: gauge_messages.Message_SpecDataStoreInit,
179			SpecDataStoreInitRequest: &gauge_messages.SpecDataStoreInitRequest{Stream: int32(e.stream)}}
180		return e.runner.ExecuteAndGetStatus(initSpecDataStoreMessage)
181	}
182	
183	func (e *specExecutor) notifyBeforeSpecHook() {
184		m := &gauge_messages.Message{MessageType: gauge_messages.Message_SpecExecutionStarting,
185			SpecExecutionStartingRequest: &gauge_messages.SpecExecutionStartingRequest{CurrentExecutionInfo: e.currentExecutionInfo, Stream: int32(e.stream)}}
186		e.pluginHandler.NotifyPlugins(m)
187		res := executeHook(m, e.specResult, e.runner)
188		e.specResult.ProtoSpec.PreHookMessages = res.Message
189		e.specResult.ProtoSpec.PreHookScreenshotFiles = res.ScreenshotFiles
190		if res.GetFailed() {
191			setSpecFailure(e.currentExecutionInfo)
192			handleHookFailure(e.specResult, res, result.AddPreHook)
193		}
194		m.SpecExecutionStartingRequest.SpecResult = gauge.ConvertToProtoSpecResult(e.specResult)
195		e.pluginHandler.NotifyPlugins(m)
196	}
197	
198	func (e *specExecutor) notifyAfterSpecHook() {
199		e.currentExecutionInfo.CurrentScenario = nil
200		m := &gauge_messages.Message{MessageType: gauge_messages.Message_SpecExecutionEnding,
201			SpecExecutionEndingRequest: &gauge_messages.SpecExecutionEndingRequest{CurrentExecutionInfo: e.currentExecutionInfo, Stream: int32(e.stream)}}
202		res := executeHook(m, e.specResult, e.runner)
203		e.specResult.ProtoSpec.PostHookMessages = res.Message
204		e.specResult.ProtoSpec.PostHookScreenshotFiles = res.ScreenshotFiles
205		if res.GetFailed() {
206			setSpecFailure(e.currentExecutionInfo)
207			handleHookFailure(e.specResult, res, result.AddPostHook)
208		}
209		m.SpecExecutionEndingRequest.SpecResult = gauge.ConvertToProtoSpecResult(e.specResult)
210		e.pluginHandler.NotifyPlugins(m)
211	}
212	
213	func (e *specExecutor) skipSpecForError(err error) {
214		logger.Error(true, err.Error())
215		validationError := validation.NewStepValidationError(&gauge.Step{LineNo: e.specification.Heading.LineNo, LineText: e.specification.Heading.Value},
216			err.Error(), e.specification.FileName, nil, "")
217		for _, scenario := range e.specification.Scenarios {
218			e.errMap.ScenarioErrs[scenario] = []error{validationError}
219		}
220		e.errMap.SpecErrs[e.specification] = []error{validationError}
221		e.specResult.Errors = e.convertErrors(e.errMap.SpecErrs[e.specification])
222		e.specResult.SetSkipped(true)
223	}
224	
225	func (e *specExecutor) failSpec() {
226		e.specResult.Errors = e.convertErrors(e.errMap.SpecErrs[e.specification])
227		e.specResult.SetFailure()
228	}
229	
230	func (e *specExecutor) convertErrors(specErrors []error) []*gauge_messages.Error {
231		var errors []*gauge_messages.Error
232		for _, e := range specErrors {
233			switch err := e.(type) {
234			case parser.ParseError:
235				errors = append(errors, &gauge_messages.Error{
236					Message:    err.Error(),
237					LineNumber: int32(err.LineNo),
238					Filename:   err.FileName,
239					Type:       gauge_messages.Error_PARSE_ERROR,
240				})
241			case validation.StepValidationError, validation.SpecValidationError:
242				errors = append(errors, &gauge_messages.Error{
243					Message: e.Error(),
244					Type:    gauge_messages.Error_VALIDATION_ERROR,
245				})
246			}
247		}
248		return errors
249	}
250	
251	func (e *specExecutor) setSkipInfo(protoStep *gauge_messages.ProtoStep, step *gauge.Step) {
252		protoStep.StepExecutionResult = &gauge_messages.ProtoStepExecutionResult{}
253		protoStep.StepExecutionResult.Skipped = false
254		if _, ok := e.errMap.StepErrs[step]; ok {
255			protoStep.StepExecutionResult.Skipped = true
256			protoStep.StepExecutionResult.SkippedReason = "Step implementation not found"
257		}
258	}
259	
260	func (e *specExecutor) getItemsForScenarioExecution(steps []*gauge.Step) ([]*gauge_messages.ProtoItem, error) {
261		items := make([]gauge.Item, len(steps))
262		for i, context := range steps {
263			items[i] = context
264		}
265		lookup, err := e.dataTableLookup()
266		if err != nil {
267			return nil, err
268		}
269		return resolveItems(items, lookup, e.setSkipInfo)
270	}
271	
272	func (e *specExecutor) dataTableLookup() (*gauge.ArgLookup, error) {
273		l := new(gauge.ArgLookup)
274		err := l.ReadDataTableRow(e.specification.DataTable.Table, 0)
275		return l, err
276	}
277	
278	func (e *specExecutor) executeScenarios(scenarios []*gauge.Scenario) ([]result.Result, error) {
279		var scenarioResults []result.Result
280		for _, scenario := range scenarios {
281			sceResult, err := e.executeScenario(scenario)
282			if err != nil {
283				return nil, err
284			}
285			scenarioResults = append(scenarioResults, sceResult)
286		}
287		return scenarioResults, nil
288	}
289	
290	func (e *specExecutor) executeScenario(scenario *gauge.Scenario) (*result.ScenarioResult, error) {
291		var scenarioResult *result.ScenarioResult
292	
293		shouldRetry := RetryOnlyTags == ""
294	
295		if !shouldRetry {
296			spec := e.specification
297			tagValues := make([]string, 0)
298			if spec.Tags != nil {
299				tagValues = spec.Tags.Values()
300			}
301	
302			specFilter := filter.NewScenarioFilterBasedOnTags(tagValues, RetryOnlyTags)
303	
304			shouldRetry = !(specFilter.Filter(scenario))
305		}
306		retriesCount := 0
307		for i := 0; i < MaxRetriesCount; i++ {
308			e.currentExecutionInfo.CurrentScenario = &gauge_messages.ScenarioInfo{
309				Name:     scenario.Heading.Value,
310				Tags:     getTagValue(scenario.Tags),
311				IsFailed: false,
312				Retries: &gauge_messages.ScenarioRetriesInfo{
313					MaxRetries:   int32(MaxRetriesCount) - 1,
314					CurrentRetry: int32(retriesCount),
315				},
316			}
317	
318			scenarioResult = &result.ScenarioResult{
319				ProtoScenario:             gauge.NewProtoScenario(scenario),
320				ScenarioDataTableRow:      gauge.ConvertToProtoTable(&scenario.ScenarioDataTableRow),
321				ScenarioDataTableRowIndex: scenario.ScenarioDataTableRowIndex,
322				ScenarioDataTable:         gauge.ConvertToProtoTable(scenario.DataTable.Table),
323			}
324			if err := e.addAllItemsForScenarioExecution(scenario, scenarioResult); err != nil {
325				return nil, err
326			}
327			e.scenarioExecutor.execute(scenario, scenarioResult)
328			retriesCount++
329			if scenarioResult.ProtoScenario.GetExecutionStatus() == gauge_messages.ExecutionStatus_SKIPPED {
330				e.specResult.ScenarioSkippedCount++
331			}
332	
333			if !shouldRetry || !scenarioResult.GetFailed() {
334				break
335			}
336		}
337		scenarioResult.ProtoScenario.RetriesCount = int64(retriesCount)
338		return scenarioResult, nil
339	}
340	
341	func (e *specExecutor) addAllItemsForScenarioExecution(scenario *gauge.Scenario, scenarioResult *result.ScenarioResult) error {
342		contexts, err := e.getItemsForScenarioExecution(e.specification.Contexts)
343		if err != nil {
344			return err
345		}
346		scenarioResult.AddContexts(contexts)
347		tearDownSteps, err := e.getItemsForScenarioExecution(e.specification.TearDownSteps)
348		if err != nil {
349			return err
350		}
351		scenarioResult.AddTearDownSteps(tearDownSteps)
352		lookup, err := e.dataTableLookup()
353		if err != nil {
354			return err
355		}
356		if scenario.ScenarioDataTableRow.IsInitialized() {
357			parser.GetResolvedDataTablerows(&scenario.ScenarioDataTableRow)
358			if err = lookup.ReadDataTableRow(&scenario.ScenarioDataTableRow, 0); err != nil {
359				return err
360			}
361		}
362		items, err := resolveItems(scenario.Items, lookup, e.setSkipInfo)
363		if err != nil {
364			return err
365		}
366		scenarioResult.AddItems(items)
367		return nil
368	}
369	
370	func getTagValue(tags *gauge.Tags) []string {
371		var tagValues []string
372		if tags != nil {
373			tagValues = append(tagValues, tags.Values()...)
374		}
375		return tagValues
376	}
377	
378	func setSpecFailure(executionInfo *gauge_messages.ExecutionInfo) {
379		executionInfo.CurrentSpec.IsFailed = true
380	}
381	
382	func shouldExecuteForRow(i int) bool {
383		if len(tableRowsIndexes) < 1 {
384			return true
385		}
386		for _, index := range tableRowsIndexes {
387			if index == i {
388				return true
389			}
390		}
391		return false
392	}
393	
394	func getDataTableRows(tableRows string) (tableRowIndexes []int) {
395		switch {
396		case strings.TrimSpace(tableRows) == "":
397			return
398		case strings.Contains(tableRows, "-"):
399			indexes := strings.Split(tableRows, "-")
400			startRow, _ := strconv.Atoi(strings.TrimSpace(indexes[0]))
401			endRow, _ := strconv.Atoi(strings.TrimSpace(indexes[1]))
402			for i := startRow - 1; i < endRow; i++ {
403				tableRowIndexes = append(tableRowIndexes, i)
404			}
405		default:
406			indexes := strings.Split(tableRows, ",")
407			for _, i := range indexes {
408				rowNumber, _ := strconv.Atoi(strings.TrimSpace(i))
409				tableRowIndexes = append(tableRowIndexes, rowNumber-1)
410			}
411		}
412		return
413	}
414	
415	func executeHook(message *gauge_messages.Message, execTimeTracker result.ExecTimeTracker, r runner.Runner) *gauge_messages.ProtoExecutionResult {
416		executionResult := r.ExecuteAndGetStatus(message)
417		execTimeTracker.AddExecTime(executionResult.GetExecutionTime())
418		return executionResult
419	}
420	
421	func hasParseError(errs []error) bool {
422		for _, e := range errs {
423			if _, ok := e.(parser.ParseError); ok {
424				return true
425			}
426		}
427		return false
428	}
